DROP TABLE IF EXISTS `expenditures`;
CREATE TABLE `expenditures` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `category` varchar(100) NOT NULL,
  `amount` decimal(15,2) NOT NULL,
  `description` text DEFAULT NULL,
  `date` date NOT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

DROP TABLE IF EXISTS `invoice_items`;
CREATE TABLE `invoice_items` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `invoice_id` varchar(50) DEFAULT NULL,
  `description` text NOT NULL,
  `quantity` int(11) DEFAULT 1,
  `rate` decimal(10,2) NOT NULL,
  `amount` decimal(10,2) NOT NULL,
  PRIMARY KEY (`id`),
  KEY `invoice_id` (`invoice_id`),
  CONSTRAINT `invoice_items_ibfk_1` FOREIGN KEY (`invoice_id`) REFERENCES `invoices` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

INSERT INTO `invoice_items` VALUES (1, 'INV-9166', 'web', 1, '10000.00', '10000.00');

DROP TABLE IF EXISTS `invoices`;
CREATE TABLE `invoices` (
  `id` varchar(50) NOT NULL,
  `client_name` varchar(100) NOT NULL,
  `total_amount` decimal(10,2) NOT NULL,
  `invoice_date` date NOT NULL,
  `status` enum('Paid','Pending','Overdue') DEFAULT 'Pending',
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

INSERT INTO `invoices` VALUES ('INV-9166', 'prashant', '11800.00', '2026-02-20 18:30:00', 'Pending', '2026-02-20 11:34:46');

DROP TABLE IF EXISTS `lead_activities`;
CREATE TABLE `lead_activities` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `lead_id` int(11) NOT NULL,
  `user_id` int(11) DEFAULT NULL,
  `type` varchar(50) DEFAULT NULL,
  `content` text DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `lead_id` (`lead_id`),
  KEY `fk_lead_activities_user_id_registry` (`user_id`),
  CONSTRAINT `fk_lead_activities_user_id_registry` FOREIGN KEY (`user_id`) REFERENCES `user_identities` (`id`) ON DELETE CASCADE,
  CONSTRAINT `lead_activities_ibfk_1` FOREIGN KEY (`lead_id`) REFERENCES `leads` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=6 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

INSERT INTO `lead_activities` VALUES (2, 2, 16, 'Lead Captured', 'Lead created by Employee CRM', '2026-02-21 06:59:39'),
(3, 3, 18, 'Lead Captured', 'Lead created by Super Admin', '2026-02-25 12:36:09'),
(4, 4, 18, 'Lead Captured', 'Lead created by Super Admin', '2026-02-25 12:36:24'),
(5, 4, 18, 'Update', 'Lead reassigned', '2026-02-25 12:36:55');

DROP TABLE IF EXISTS `lead_reminders`;
CREATE TABLE `lead_reminders` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `lead_id` int(11) NOT NULL,
  `user_id` int(11) NOT NULL,
  `reminder_date` datetime NOT NULL,
  `message` text DEFAULT NULL,
  `is_completed` tinyint(1) DEFAULT 0,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `lead_id` (`lead_id`),
  KEY `fk_lead_reminders_user_id_registry` (`user_id`),
  CONSTRAINT `fk_lead_reminders_user_id_registry` FOREIGN KEY (`user_id`) REFERENCES `user_identities` (`id`) ON DELETE CASCADE,
  CONSTRAINT `lead_reminders_ibfk_1` FOREIGN KEY (`lead_id`) REFERENCES `leads` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=3 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

INSERT INTO `lead_reminders` VALUES (2, 2, 2, '2026-02-24 04:41:00', 'do it', 1, '2026-02-23 04:41:42');

DROP TABLE IF EXISTS `leads`;
CREATE TABLE `leads` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `name` varchar(255) NOT NULL,
  `email` varchar(255) DEFAULT NULL,
  `phone` varchar(20) DEFAULT NULL,
  `source` varchar(100) DEFAULT NULL,
  `status` enum('New','Contacted','Qualified','Converted') DEFAULT 'New',
  `score` enum('Hot','Warm','Cold') DEFAULT 'Warm',
  `assigned_to` int(11) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `fk_leads_assigned_to_registry` (`assigned_to`),
  CONSTRAINT `fk_leads_assigned_to_registry` FOREIGN KEY (`assigned_to`) REFERENCES `user_identities` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

