DROP TABLE IF EXISTS `notifications`;
CREATE TABLE `notifications` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `user_id` int(11) NOT NULL,
  `title` varchar(255) NOT NULL,
  `message` text NOT NULL,
  `type` enum('info','success','warning','error') DEFAULT 'info',
  `is_read` tinyint(1) DEFAULT 0,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `triggered_by` int(11) DEFAULT NULL,
  `action_type` varchar(255) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `fk_notifications_user_id_registry` (`user_id`),
  KEY `fk_notifications_triggered_by_registry` (`triggered_by`),
  CONSTRAINT `fk_notifications_triggered_by_registry` FOREIGN KEY (`triggered_by`) REFERENCES `user_identities` (`id`) ON DELETE CASCADE,
  CONSTRAINT `fk_notifications_user_id_registry` FOREIGN KEY (`user_id`) REFERENCES `user_identities` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=146 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

