DROP TABLE IF EXISTS `tickets`;
CREATE TABLE `tickets` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `user_id` int(11) NOT NULL,
  `assigned_to` int(11) DEFAULT NULL,
  `title` varchar(255) NOT NULL,
  `description` text DEFAULT NULL,
  `priority` enum('Low','Medium','High','Critical') DEFAULT 'Medium',
  `status` enum('Open','In Progress','Resolved','Closed') DEFAULT 'Open',
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `category` varchar(255) DEFAULT 'Issue',
  PRIMARY KEY (`id`),
  KEY `fk_tickets_user_id_registry` (`user_id`),
  KEY `fk_tickets_assigned_to_registry` (`assigned_to`),
  CONSTRAINT `fk_tickets_assigned_to_registry` FOREIGN KEY (`assigned_to`) REFERENCES `user_identities` (`id`) ON DELETE CASCADE,
  CONSTRAINT `fk_tickets_user_id_registry` FOREIGN KEY (`user_id`) REFERENCES `user_identities` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=18 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

