DROP TABLE IF EXISTS `vendor_tools`;
CREATE TABLE `vendor_tools` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `vendor_user_id` int(11) NOT NULL,
  `tool_name` varchar(100) NOT NULL,
  `tool_key` varchar(50) NOT NULL,
  `description` text DEFAULT NULL,
  `icon` varchar(50) DEFAULT 'Box',
  `enabled` tinyint(1) DEFAULT 1,
  `assigned_by` int(11) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `tool_url` varchar(255) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `vendor_user_id` (`vendor_user_id`),
  CONSTRAINT `vendor_tools_ibfk_1` FOREIGN KEY (`vendor_user_id`) REFERENCES `user_identities` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

